import { addEdge as addEdgeSystem, createDevWarn, } from '@xyflow/system';
const defaultOnError = createDevWarn('Svelte Flow', 'https://svelteflow.dev/');
export function addEdge(edgeParams, edges, options = {}) {
    return addEdgeSystem(edgeParams, edges, {
        ...options,
        onError: options.onError ?? defaultOnError,
    });
}
